// ─── ALGORITMO ROUND-ROBIN PONDERADO ───────────────────────────
// Recibe todos los tickets pendientes y todos los agentes activos.
// Distribuye de forma equitativa: el agente con menos carga siempre
// recibe el siguiente ticket. Garantía: diferencia máxima de 1 ticket.

// Obtener tickets del nodo anterior
const ticketsRaw = $('Obtener pendientes sin agente').all();
const agentesRaw = $('Obtener agentes activos').all();

const tickets = ticketsRaw.map(i => i.json);
const agentes = agentesRaw.map(i => ({
  id: i.json.id,
  nombre: i.json.nombre,
  email: i.json.email,
  casos_activos: parseInt(i.json.casos_activos) || 0
}));

if (!agentes.length) {
  return [{ json: { error: 'No hay agentes activos', asignaciones: [], distribucion: [] } }];
}

// Carga extra acumulada en esta ejecución (no persistida aún)
const cargaExtra = {};
agentes.forEach(ag => cargaExtra[ag.id] = 0);

const asignaciones = [];

for (const ticket of tickets) {
  // Ordenar agentes por carga total (activos + extra de esta ejecución)
  agentes.sort((a, b) => {
    const cargaA = a.casos_activos + cargaExtra[a.id];
    const cargaB = b.casos_activos + cargaExtra[b.id];
    if (cargaA !== cargaB) return cargaA - cargaB;
    // Desempate por nombre (consistencia)
    return a.nombre.localeCompare(b.nombre);
  });

  const agente = agentes[0];
  cargaExtra[agente.id]++;

  asignaciones.push({
    correo_id: ticket.id,
    ticket_id: ticket.ticket_id || ticket.id,
    agente_id: agente.id,
    agente_nombre: agente.nombre,
    agente_email: agente.email,
    carga_resultante: agente.casos_activos + cargaExtra[agente.id]
  });
}

// Resumen por agente para el preview y el log
const distribucion = agentes.map(ag => ({
  agente_id: ag.id,
  agente: ag.nombre,
  email: ag.email,
  tickets_nuevos: cargaExtra[ag.id],
  casos_activos_antes: ag.casos_activos,
  casos_activos_despues: ag.casos_activos + cargaExtra[ag.id]
})).filter(d => d.tickets_nuevos > 0);

return [{ json: {
  asignaciones,
  distribucion,
  total: asignaciones.length,
  agentes_involucrados: distribucion.length
}}];

// ─── EJECUTAR TODOS LOS PATCHes EN SECUENCIA ─────────────────────
// Recibe asignaciones del algoritmo y ejecuta los PATCHes en Supabase
// Más confiable que splitInBatches para operaciones masivas

const { asignaciones, distribucion, total } = $input.first().json;

const SB_URL  = 'https://yeiupcumvdvdswfhcoty.supabase.co/rest/v1';
const SB_KEY  = $credentials.supabaseServiceKey;

const headers = {
  'apikey': SB_KEY,
  'Authorization': 'Bearer ' + SB_KEY,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};

let exitosos = 0;
let errores = [];

// 1. PATCH todos los correos (asignar agente + cambiar estado)
for (const asig of asignaciones) {
  try {
    const r = await $http.request({
      method: 'PATCH',
      url: `${SB_URL}/correos?id=eq.${asig.correo_id}`,
      headers,
      body: JSON.stringify({
        agente_id: asig.agente_id,
        asignado_a: asig.agente_nombre,
        estado: 'gestion'
      })
    });
    exitosos++;
  } catch(e) {
    errores.push({ correo_id: asig.correo_id, error: e.message });
  }
}

// 2. PATCH casos_activos de cada agente (una sola vez por agente)
const agentesCargaFinal = {};
for (const asig of asignaciones) {
  agentesCargaFinal[asig.agente_id] = asig.carga_resultante;
}

for (const [agenteId, cargaFinal] of Object.entries(agentesCargaFinal)) {
  try {
    await $http.request({
      method: 'PATCH',
      url: `${SB_URL}/agentes?id=eq.${agenteId}`,
      headers,
      body: JSON.stringify({ casos_activos: cargaFinal })
    });
  } catch(e) {
    errores.push({ agente_id: agenteId, error: e.message });
  }
}

return [{
  json: {
    ok: errores.length === 0,
    total_asignados: exitosos,
    distribucion,
    errores: errores.length > 0 ? errores : undefined,
    mensaje: `Se asignaron ${exitosos} tickets de forma equitativa entre ${distribucion.length} agente(s).`
  }
}];
